export async function getRegistrationNonce(address: string): Promise<string> {
  if (!address) {
    throw new Error("Wallet address not available");
  }

  const noncePayload = await orderlyApi<{
    success?: boolean;
    message?: string;
    data?: { registration_nonce?: string };
  }>({
    endpoint: `/v1/registration_nonce?address=${encodeURIComponent(address)}`,
    token: null,
    showToastOnError: false,
  });
  const registrationNonce = noncePayload.data?.registration_nonce;
  if (!registrationNonce) {
    throw new Error(
      noncePayload.message || "Failed to create registration nonce."
    );
  }

  return registrationNonce;
}

