export async function checkBrokerIdAvailability(
  brokerId: string
): Promise<boolean> {
  type BrokerIdAvailabilityResponse = {
    success?: boolean;
    code?: number;
    message?: string;
    data?: { rows?: unknown[] };
  };

  let data: BrokerIdAvailabilityResponse;
  try {
    data = await orderlyApi<BrokerIdAvailabilityResponse>({
      endpoint: `/v1/public/broker/name?broker_id=${encodeURIComponent(brokerId)}`,
      token: null,
      showToastOnError: false,
    });
  } catch (error) {
    const errorData = (error as { data?: BrokerIdAvailabilityResponse }).data;
    if (
      errorData?.success === false &&
      errorData.code === -1101 &&
      errorData.message === "Broker ID does not exist"
    ) {
      return true;
    }
    throw error;
  }

  if (
    data.success === false &&
    data.code === -1101 &&
    data.message === "Broker ID does not exist"
  ) {
    return true;
  }

  if (data.success === false) {
    throw new Error(data.message || "Failed to check broker ID availability.");
  }

  if (data.success === true) {
    return false;
  }

  throw new Error("Failed to check broker ID availability.");
}

