let dexCreatorDexStatusCache: {
  value: DexCreatorDexStatus | null;
  expiresAt: number;
  token: string | null;
  baseUrl: string;
} | null = null;
let dexCreatorDexStatusInflight: Promise<DexCreatorDexStatus | null> | null =
  null;

export function invalidateDexCreatorDexStatusCache() {
  dexCreatorDexStatusCache = null;
  dexCreatorDexStatusInflight = null;
}

export async function fetchDexCreatorDexStatus(
  options: { force?: boolean } = {}
): Promise<DexCreatorDexStatus | null> {
  const token =
    typeof window !== "undefined" ? walletGetItem("auth_token") : null;
  const baseUrl = getOrderlyEnvConfig().dexApiBaseUrl;
  if (!token || !baseUrl) return null;

  const now = Date.now();
  if (
    !options.force &&
    dexCreatorDexStatusCache &&
    dexCreatorDexStatusCache.expiresAt > now &&
    dexCreatorDexStatusCache.token === token &&
    dexCreatorDexStatusCache.baseUrl === baseUrl
  ) {
    return dexCreatorDexStatusCache.value;
  }
  if (dexCreatorDexStatusInflight) return dexCreatorDexStatusInflight;

  dexCreatorDexStatusInflight = orderlyApi<unknown>({
    endpoint: "/api/dex",
    baseUrl,
    token,
  })
    .then(payload => {
      const normalized = normalizeDexCreatorDexStatus(payload);
      dexCreatorDexStatusCache = {
        value: normalized,
        expiresAt: Date.now() + 30_000,
        token,
        baseUrl,
      };
      return normalized;
    })
    .finally(() => {
      dexCreatorDexStatusInflight = null;
    });

  return dexCreatorDexStatusInflight;
}

