async function fetchGraduationStatus(
  token: string
): Promise<GraduationStatusResponse | null> {
  try {
    return await orderlyApi<GraduationStatusResponse>({
      endpoint: "/api/graduation/graduation-status",
      baseUrl: getOrderlyEnvConfig().dexApiBaseUrl,
      token,
    });
  } catch (error) {
    const apiError = error as Error & { status?: number; data?: unknown };
    const message =
      typeof apiError.data === "object" &&
      apiError.data &&
      "message" in apiError.data
        ? String((apiError.data as { message?: unknown }).message)
        : apiError.message;
    if (
      apiError.status === 400 &&
      message.toLowerCase().includes("create a dex")
    ) {
      return { success: false, noDexProfile: true };
    }
    const status = apiError.status;
    if (status === 400 || status === 404) return null;
    throw error;
  }
}

export async function resolveWalletAccount(
  walletAddress: string,
  authToken?: string,
  options: { skipAmbassadorCheck?: boolean } = {}
): Promise<WalletAccountResolution> {
  const normalized = walletAddress.toLowerCase();

  if (typeof window === "undefined") return { kind: "free" };

  if (!options.skipAmbassadorCheck) {
    const ambassadorAccount = await fetchAmbassadorAccount(walletAddress);
    if (ambassadorAccount) {
      return {
        kind: "ambassador",
        brokerId: "ambassador",
        accountId: ambassadorAccount.account_id,
      };
    }
  }

  const token = authToken || walletGetItem("auth_token");
  if (token) {
    const isValid = await validateDexCreatorAuth(walletAddress, token);
    if (!isValid) return { kind: "free" };

    const dexStatus = await fetchDexCreatorDexStatus();
    const graduationStatus = await fetchGraduationStatus(token);

    if (graduationStatus?.noDexProfile) return { kind: "free" };

    if (dexStatus && dexStatus.exists !== false && dexStatus.id) {
      const brokerId = graduationStatus?.brokerId || dexStatus.brokerId;
      const hasGraduatedBrokerId = Boolean(brokerId && brokerId !== "demo");
      return {
        kind: "builder",
        dexId: dexStatus.id,
        brokerId,
        builderName: dexStatus.brokerName,
        dexConfigured: true,
        graduated: hasGraduatedBrokerId,
        adminRegistered:
          hasGraduatedBrokerId && graduationStatus?.isGraduated === true,
        pathway:
          dexStatus.integrationType === "low_code"
            ? "low-code"
            : dexStatus.integrationType === "custom"
              ? "sdk"
              : undefined,
        primaryLogo: dexStatus.primaryLogo,
        secondaryLogo: dexStatus.secondaryLogo,
        logo: dexStatus.primaryLogo || dexStatus.secondaryLogo || null,
        isMultisig: graduationStatus?.isMultisig,
        multisigAddress: graduationStatus?.multisigAddress,
        multisigChainId: graduationStatus?.multisigChainId,
      };
    }
  }

  const profileRaw = walletGetItem("orderlyProfile");
  const contextRaw = walletGetItem("orderlyLoginContext");
  let profile: {
    role?: string;
    brokerId?: string;
    builderName?: string;
  } | null = null;
  let context: { walletAddress?: string } | null = null;

  try {
    profile = profileRaw ? JSON.parse(profileRaw) : null;
  } catch {
    profile = null;
  }

  try {
    context = contextRaw ? JSON.parse(contextRaw) : null;
  } catch {
    context = null;
  }

  const contextMatchesWallet =
    !context?.walletAddress ||
    context.walletAddress.toLowerCase() === normalized;
  if (
    !options.skipAmbassadorCheck &&
    contextMatchesWallet &&
    profile?.role === "ambassador" &&
    profile.brokerId === "ambassador"
  ) {
    return {
      kind: "ambassador",
      brokerId: "ambassador",
      distributorName: profile.builderName,
    };
  }

  const dexId = walletGetItem("orderlyDexId");
  if (
    dexId ||
    (contextMatchesWallet &&
      profile?.builderName &&
      profile.role !== "ambassador")
  ) {
    return {
      kind: "builder",
      dexId: dexId || profile?.brokerId || "orderly-one-builder",
      brokerId: profile?.brokerId,
      builderName: profile?.builderName,
    };
  }

  return { kind: "free" };
}
